// =============================================================
// 🧱 A6 — STEP com TELEMETRIA TOTAL (blindagem máxima)
// =============================================================
async function step(env, st, messages, nextStage, options = {}) {

  const simCtx = getSimulationContext(env);
  const isSim = Boolean(simCtx?.active);
  const requireSendSuccess = options?.requireSendSuccess === true;
  const currentStage = st?.fase_conversa || "inicio";

  // Converte sempre para array
  const rawArr = Array.isArray(messages) ? messages : [messages];

  // Reconciliar input do cliente para detectar overlap/múltiplas intenções.
  // rawArr é passado como mechanical_prompt_source — fonte de intenção, NUNCA fala final.
  // Ephemeral — descartado logo abaixo após renderizar.
  if (!st.__round_intent && (st.last_user_text || "").trim()) {
    st.__round_intent = buildRoundIntent(st, st.last_user_text, rawArr);
  }

  // Camada canônica de fala cognitiva soberana.
  // Toda fala visível ao cliente passa por renderCognitiveSpeech().
  // O mecânico permanece soberano em stage/gate/nextStage/persistência.
  const arr = renderCognitiveSpeech(st, currentStage, rawArr.filter(Boolean));

  // ── BLOCO D: Blindagem pós-LLM ──
  // Depois que o árbitro soberano decidiu a fala, nenhum helper pode reescrever
  // a semântica. Apenas guardrail mínimo estrito é permitido.
  const speechArbiterSource = st.__speech_arbiter_source || "extreme_fallback";

  // ── TELEMETRIA SOBERANA OBRIGATÓRIA (Item 5: prova output_surface) ────────
  // Captura antes de limpar flags transitórias.
  const _llmResponseForTelemetry = String(st.__cognitive_reply_prefix || "").trim();
  const _outputSurface = arr.join("\n");
  const _surfaceEqualLlm = speechArbiterSource === "llm_real"
    ? (_outputSurface === _llmResponseForTelemetry)
    : null;
  const _mechanicalTextCandidate = rawArr.filter(Boolean).join("\n");
  const _mechanicalTextBlocked = speechArbiterSource === "llm_real";

  // ── HYBRID TELEMETRY PR2: Hook 3 — Post-processing / Final Contract ──
  try {
    emitPostProcessingTelemetry({
      st,
      stage: currentStage,
      replyBeforeContract: _llmResponseForTelemetry || _mechanicalTextCandidate,
      replyAfterContract: _outputSurface,
      surfaceChanged: speechArbiterSource === "llm_real"
        ? (_outputSurface !== _llmResponseForTelemetry)
        : (_outputSurface !== _mechanicalTextCandidate)
    }).catch(() => {});
  } catch (_) { /* telemetry must never break the flow */ }

  // ── TELEMETRIA: separação de responsabilidades no step() ──
  // Prova em runtime que: surface === reply_text, worker não reescreveu fala
  try {
    const _stepSepTelemetry = buildSeparationTelemetry({
      stage_before: currentStage,
      stage_after: nextStage || currentStage,
      reply_text_from_cognitive: speechArbiterSource === "llm_real" ? _llmResponseForTelemetry : null,
      signal_from_cognitive: null,
      signal_validated_by_worker: false,
      signal_validation_result: null,
      surface_sent_to_customer: _outputSurface,
      needs_confirmation: false,
      confidence: null,
      advance_allowed: Boolean(nextStage && nextStage !== currentStage),
      advance_block_reason: null
    });
    _stepSepTelemetry.worker_rewrote_reply = speechArbiterSource === "llm_real"
      ? (_outputSurface !== _llmResponseForTelemetry)
      : false;
    _stepSepTelemetry.surface_equal_reply_text = speechArbiterSource === "llm_real"
      ? (_outputSurface === _llmResponseForTelemetry)
      : null;

    // ── PASSO 2 TELEMETRIA OBRIGATÓRIA ──
    // Campos obrigatórios para provar redução de arbitragem do worker.
    const _renderPathUsed = st.__render_path_used || "unknown";
    const _isTopoStage = (currentStage === "inicio" || currentStage === "inicio_decisao" || currentStage === "inicio_programa");
    _stepSepTelemetry.cognitive_path_used = (speechArbiterSource === "llm_real");
    _stepSepTelemetry.legacy_topo_path_used = (_isTopoStage && speechArbiterSource !== "llm_real");
    _stepSepTelemetry.worker_conversational_override_used = (speechArbiterSource === "llm_real")
      ? (_outputSurface !== _llmResponseForTelemetry)
      : false;
    _stepSepTelemetry.render_path_used = _renderPathUsed;
    _stepSepTelemetry.nextStage = nextStage || null;
    _stepSepTelemetry.contract_final_changed_reply = (speechArbiterSource === "llm_real")
      ? (_outputSurface !== _llmResponseForTelemetry)
      : false;
    _stepSepTelemetry.topo_special_case_used = (_isTopoStage && _renderPathUsed === "topo_sealed_bucket_static");

    await telemetry(env, {
      wa_id: st.wa_id,
      event: "step_separation_proof",
      stage: currentStage,
      next_stage: nextStage || null,
      severity: "info",
      message: "Prova de separação no step() — surface vs reply_text — Passo 2",
      details: _stepSepTelemetry
    });
  } catch (_stepSepErr) { /* telemetry must never break the flow */ }

  // limpa flags transitórias para não vazar para próximas respostas
  st.__cognitive_reply_prefix = null;
  st.__cognitive_v2_takes_final = false;
  st.__round_intent = null;
  st.__speech_arbiter_source = null;
  st.__render_path_used = null;

  // 🔥 AQUI: aplica modo humano SOMENTE se modo humano MANUAL legítimo do painel
  // (BLOCO F: modoHumanoRender não reescreve superfície cognitiva automática)
  const msgs = modoHumanoRender(st, arr);
  const replyText = msgs.join("\n");

  emitCognitiveTelemetry(st, {
    point: "after_response_assembled",
    currentStage,
    nextStage: nextStage || currentStage,
    replyText
  });

  // ── TELEMETRIA SOBERANA — prova de igualdade strict (Item 2 + 5) ──────
  try {
    await telemetry(env, {
      wa_id: st.wa_id,
      event: "sovereign_surface_proof",
      stage: currentStage,
      next_stage: nextStage || null,
      severity: "info",
      message: "Prova de superfície soberana — step()",
      details: {
        user_text: st.last_user_text || null,
        normalized_user_text: normalizeText(st.last_user_text || ""),
        origin: speechArbiterSource,
        llm_response_after_contract: speechArbiterSource === "llm_real" ? _llmResponseForTelemetry : null,
        output_surface: _outputSurface,
        surface_source: speechArbiterSource,
        stage_before: currentStage,
        stage_after: nextStage || currentStage,
        nextStage: nextStage || null,
        mechanical_text_candidate: _mechanicalTextCandidate.slice(0, 300),
        mechanical_text_blocked: _mechanicalTextBlocked,
        surface_equal_llm: _surfaceEqualLlm,
        replay_suspected: false,
        opener_override_used: false,
        cognitive_v2_takes_final: speechArbiterSource === "llm_real",
        speech_arbiter_source: speechArbiterSource
      }
    });
  } catch (_telErr) {
    console.error("SOVEREIGN_SURFACE_PROOF_TELEMETRY_ERROR:", _telErr);
  }

  // ── HYBRID TELEMETRY PR2: Hook 4 — Mechanical Decision ──
  try {
    emitMechanicalDecisionTelemetry({
      st,
      stageBefore: currentStage,
      stageAfter: nextStage || currentStage,
      parserUsed: null,
      parserResult: null,
      mechanicalAction: nextStage && nextStage !== currentStage ? "stage_advance" : "stay",
      validationResult: null,
      reaskTriggered: false,
      stageLocked: false,
      stateDiff: null
    }).catch(() => {});
  } catch (_) { /* telemetry must never break the flow */ }

  // ── HYBRID TELEMETRY PR3: Hook 7 — Stage Symptoms ──
  // Reads ephemeral __tel_* flags set by the COGNITIVE ASSIST block (if present),
  // then clears them so they don't leak into the next turn.
  try {
    const _telCogSignal = st.__tel_cognitive_signal || null;
    const _telCogConf = st.__tel_cognitive_confidence ?? null;
    const _telOverride = Boolean(st.__tel_override_suspected);
    st.__tel_cognitive_signal = null;
    st.__tel_cognitive_confidence = null;
    st.__tel_override_suspected = null;
    emitStageSymptomsHook({
      st,
      stageBefore: currentStage,
      stageAfter: nextStage || currentStage,
      reaskTriggered: false,
      stageLocked: false,
      cognitiveSignal: _telCogSignal,
      cognitiveConfidence: _telCogConf,
      mechanicalAction: nextStage && nextStage !== currentStage ? "stage_advance" : "stay",
      overrideSuspected: _telOverride,
      stateDiff: null
    }).catch(() => {});
  } catch (_) { /* telemetry must never break the flow */ }

  // ── HYBRID TELEMETRY PR2: Hook 6 — Final Output ──
  try {
    emitFinalOutputTelemetry({
      st,
      stageBefore: currentStage,
      stageAfter: nextStage || currentStage,
      outputSurface: _outputSurface,
      surfaceEqualLlm: _surfaceEqualLlm,
      mechanicalTextCandidate: _mechanicalTextCandidate,
      mechanicalTextBlocked: _mechanicalTextBlocked,
      speechArbiterSource
    }).catch(() => {});
  } catch (_) { /* telemetry must never break the flow */ }

  if (isSim) {
    simCtx.messageLog = Array.isArray(simCtx.messageLog) ? simCtx.messageLog : [];
    simCtx.messageLog.push({
      wa_id: st?.wa_id || null,
      stage_before: currentStage,
      stage_after: nextStage || currentStage || null,
      messages: msgs
    });
  }

  try {
    // ============================================================
    // 🛰 TELEMETRIA — Saída / transição de estágio (geral)
    // ============================================================
    await telemetry(env, {
      wa_id: st.wa_id,
      event: "funnel_output",
      stage: currentStage,
      next_stage: nextStage || null,
      severity: "info",
      message: "Saída do step() — transição de fase",
      details: {
        messages_out: msgs,
        stage_before: currentStage,
        stage_after: nextStage,
        last_user_text: st.last_user_text || null,
        array_len: msgs.length,
        first_msg: msgs[0],
        last_msg: msgs[msgs.length - 1]
      }
    });

    // ============================================================
    // 🛰 TELEMETRIA — LEAVE_STAGE (funil interno)
    // ============================================================
    await funnelTelemetry(env, {
      wa_id: st.wa_id,
      event: "leave_stage",
      from_stage: currentStage,
      to_stage: nextStage,
      user_text: st.last_user_text || null,
      severity: "info",
      message: "Transição de estágio detectada (LEAVE_STAGE)"
    });

    // ============================================================
    // Atualiza estado do funil
    // ============================================================
    if (nextStage) {

      // 🔍 LOG PARA DEBUGAR SE A FASE ESTÁ SENDO ATUALIZADA
      console.log("UPDATE_FASE:", {
        wa_id: st.wa_id,
        before: currentStage,
        after: nextStage
      });

      // ✅ SIMULAÇÃO: atualiza o state em memória (sem IO real)
      if (isSim) {
        st.fase_conversa = nextStage;
        st.last_bot_msg = msgs[msgs.length - 1] || null;

        await upsertState(env, st.wa_id, {
          fase_conversa: nextStage,
          last_bot_msg: msgs[msgs.length - 1] || null
        });
      } else {
        // Atualiza estado no Supabase (somente no fluxo real)
        await upsertState(env, st.wa_id, {
          fase_conversa: nextStage,
          last_bot_msg: msgs[msgs.length - 1] || null,
          updated_at: new Date().toISOString()
        });
      }

      // 🏥 Attendance Meta — sync stage transition (non-blocking)
      // Override fase_conversa with nextStage to reflect the NEW stage after transition
      try {
        await syncAttendanceMeta(env, { ...st, fase_conversa: nextStage }, { type: "stage_transition" });
      } catch (_) { /* non-blocking */ }

      // 📋 CRM Stage History — registra passagem permanente pela etapa (non-blocking)
      const _crmEtapa = CRM_STAGE_MAP[nextStage];
      if (_crmEtapa) {
        try { await upsertCrmStageHistory(env, st.wa_id, _crmEtapa); } catch (_) { /* non-blocking */ }
      }
    }

    // ============================================================
    // Envia mensagens uma a uma (delay humano real)
    // ============================================================
    for (const msg of msgs) {
      await logger(env, {
        tag: "DECISION_OUTPUT",
        wa_id: st.wa_id,
        meta_type: "text",
        meta_text: msg,
        details: {
          stage: st.fase_conversa || null,
          next_stage: nextStage || null
        }
      });

      if (!isSim) {
        const sent = await sendMessage(env, st.wa_id, msg);
        if (requireSendSuccess && !isSendMessageSuccessful(sent)) {
          const msgPreview = String(msg || "").trim().slice(0, 120);
          const sendErr = new Error(`step_send_failed:${st?.wa_id || "unknown"}:${nextStage || ""}:${msgPreview}`);
          sendErr.code = "step_send_failed";
          sendErr.wa_id = st?.wa_id || null;
          sendErr.next_stage = nextStage || null;
          sendErr.message_preview = msgPreview || null;
          throw sendErr;
        }
      }

      // Telemetria por mensagem enviada (modo verbose)
      if (env.TELEMETRIA_LEVEL === "verbose") {
        await telemetry(env, {
          wa_id: st.wa_id,
          event: "msg_enviada",
          stage: st.fase_conversa,
          severity: "debug",
          message: `Mensagem enviada: "${msg}"`,
          details: { msg }
        });
      }

      await new Promise((r) =>
        setTimeout(r, Number(env.ENOVA_DELAY_MS) || 1200)
      );
    }

    // 🏥 Attendance Meta — sync ENOVA interaction (non-blocking)
    if (!isSim && msgs.length > 0) {
      try {
        await syncAttendanceMeta(env, st, { type: "enova_message" });
      } catch (_) { /* non-blocking */ }
    }

    if (isSim) {
      emitCognitiveTelemetry(st, {
        point: "before_return_response",
        currentStage,
        nextStage: nextStage || currentStage,
        replyText
      });
      clearCognitiveTelemetryState(st);
      return {
        ok: true,
        simulated: true,
        stage_after: nextStage || st.fase_conversa || null,
        messages: msgs
      };
    }

    emitCognitiveTelemetry(st, {
      point: "before_return_response",
      currentStage,
      nextStage: nextStage || currentStage,
      replyText
    });
    clearCognitiveTelemetryState(st);
    return new Response("OK", { status: 200 });
  } catch (err) {
    clearCognitiveTelemetryState(st);
    // ============================================================
    // 🛑 TELEMETRIA — ERRO CRÍTICO NO STEP
    // ============================================================
    await telemetry(env, {
      wa_id: st.wa_id,
      event: "step_critical_error",
      stage: st.fase_conversa || "inicio",
      next_stage: nextStage || null,
      severity: "critical",
      message: "ERRO CRÍTICO no step()",
      details: {
        error: err.stack || String(err),
        messages_out: arr,
        last_user_text: st.last_user_text,
        nextStage
      }
    });

    console.error("Erro no step():", err);

    // 🚨 INCIDENT — step critical error (objective proof: caught exception)
    try { await openIncidentIfNeeded(env, st, { incident_type: "WORKER_EXCEPTION", incident_severity: "CRITICAL", error_message_short: "Erro crítico no step()", error_message_raw: err?.stack || String(err), suspected_trigger: "step_catch" }); } catch (_) { /* non-blocking */ }

    if (requireSendSuccess) {
      throw err;
    }

    // ============================================================
    // 🔥 FAILSAFE ABSOLUTO — Funil nunca morre
    // ============================================================
    return new Response(
      JSON.stringify({
        messages: [
          "Opa, deu uma travadinha aqui 😅",
          "Pode repetir pra mim rapidinho? Só pra garantir que seguimos certinho."
        ],
        nextStage: st.fase_conversa
      }),
      {
        status: 200,
        headers: { "Content-Type": "application/json" }
      }
    );
  }
}

// =============================================================
// 🧱 A7 — sendMessage() com blindagem total + telemetria META
// =============================================================
async function sendMessage(env, wa_id, text, options = {}) {
  const simCtx = getSimulationContext(env);
  if (simCtx?.suppressExternalSend) {
    const preview = {
      messaging_product: "whatsapp",
      to: wa_id,
      type: "text",
      text: { body: text }
    };

    simCtx.sendPreview = preview;
    simCtx.wouldSend = true;

    if (options.returnMeta) {
      return {
        ok: true,
        meta_status: 200,
        message_id: "dry_run_suppressed",
        suppressed: true,
        send_payload_preview: preview
      };
    }

    return true;
  }

  const url = `https://graph.facebook.com/${env.META_API_VERSION}/${env.PHONE_NUMBER_ID}/messages`;

  const payload = {
    messaging_product: "whatsapp",
    to: wa_id,
    type: "text",
    text: { body: text }
  };

  let res;

  try {
    res = await fetch(url, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${env.WHATS_TOKEN}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify(payload)
    });
  } catch (err) {
    // FALHA DE REDE / DNS / WHATSAPP FORA
    await telemetry(env, {
      wa_id,
      event: "meta_network_error",
      stage: "sendMessage",
      severity: "critical",
      message: "Falha de rede ao enviar mensagem ao WhatsApp",
      details: {
        url,
        payload,
        error: err.stack || String(err),
        hint: "Possível queda da Meta / Cloudflare DNS / Proxy"
      }
    });

    await logger(env, {
      tag: "SEND_FAIL",
      wa_id,
      details: {
        stage: "sendMessage",
        error: err?.message || String(err),
        payload_enviado: payload
      }
    });

    console.error("Erro sendMessage (network):", err);
    // 🚨 INCIDENT — network failure sending message (objective proof: fetch exception)
    try { await openIncidentIfNeeded(env, { wa_id, fase_conversa: "sendMessage" }, { incident_type: "MESSAGE_SEND_FAILURE", incident_severity: "CRITICAL", error_message_short: "Falha de rede ao enviar mensagem WhatsApp", error_message_raw: err?.stack || String(err), suspected_trigger: "sendMessage_network_catch" }); } catch (_) { /* non-blocking */ }
    if (options.returnMeta) {
      return {
        ok: false,
        meta_status: null,
        message_id: null
      };
    }
    return false;
  }

  if (!res.ok) {
    const textErr = await res.text();

    // ERRO HTTP — TOKEN, PHONE ID, 429, 400, JSON INVÁLIDO, ETC
    await telemetry(env, {
      wa_id,
      event: "meta_http_error",
      stage: "sendMessage",
      severity: res.status === 429 ? "warning" : "error",
      message: "Erro HTTP na API Meta WhatsApp",
      details: {
        url,
        payload,
        status: res.status,
        response: textErr,
        hint: mapMetaError(res.status)
      }
    });

    await logger(env, {
      tag: "SEND_FAIL",
      wa_id,
      details: {
        stage: "sendMessage",
        status: res.status,
        provider_response: textErr,
        payload_enviado: payload
      }
    });

    console.error("Erro sendMessage (HTTP):", res.status, textErr);
    // 🚨 INCIDENT — HTTP error sending message (objective proof: non-2xx status)
    try { await openIncidentIfNeeded(env, { wa_id, fase_conversa: "sendMessage" }, { incident_type: "MESSAGE_SEND_FAILURE", incident_severity: res.status === 429 ? "MEDIUM" : "HIGH", error_message_short: `Erro HTTP ${res.status} na API Meta WhatsApp`, error_message_raw: textErr ? String(textErr).slice(0, 4000) : null, suspected_trigger: `sendMessage_http_${res.status}` }); } catch (_) { /* non-blocking */ }
    if (options.returnMeta) {
      return {
        ok: false,
        meta_status: res.status,
        message_id: null
      };
    }
    return false;
  }

  // SUCESSO — salvar envio
  await telemetry(env, {
    wa_id,
    event: "meta_send_success",
    stage: "sendMessage",
    severity: "info",
    message: "Mensagem enviada com sucesso",
    details: {
      payload,
      status: res.status
    }
  });

  let providerResponse = null;
  let providerMessageId = null;

  try {
    const rawBody = await res.text();
    if (rawBody) {
      try {
        providerResponse = JSON.parse(rawBody);
      } catch {
        providerResponse = rawBody;
      }
    }

    if (providerResponse && typeof providerResponse === "object") {
      const firstMessage = Array.isArray(providerResponse.messages)
        ? providerResponse.messages[0]
        : null;

      providerMessageId = firstMessage?.id || null;
    }
  } catch (parseErr) {
    providerResponse = {
      parse_error: parseErr?.message || String(parseErr)
    };
  }

  await logger(env, {
    tag: "SEND_OK",
    wa_id,
    details: {
      stage: "sendMessage",
      status: res.status,
      payload_enviado: payload,
      provider_response: providerResponse,
      provider_message_id: providerMessageId
    }
  });

  if (options.returnMeta) {
    return {
      ok: true,
      meta_status: res.status,
      message_id: providerMessageId
    };
  }

  return true;
}

function isSendMessageSuccessful(result) {
  return result === true || (result && result.ok === true);
}

// =============================================================
// 🧱 A7.1 — MAPEAR ERROS META
// =============================================================
function mapMetaError(code) {
  switch (code) {
    case 400:
      return "Formato inválido / Phone ID errado / body malformado";
    case 401:
      return "Token inválido / expirado";
    case 403:
      return "Número sem permissão / mensagem bloqueada";
    case 404:
      return "Phone Number ID não encontrado";
    case 409:
      return "Conflito interno Meta (tente novamente)";
    case 413:
      return "Mensagem muito grande";
    case 422:
      return "Campo obrigatório ausente";
    case 429:
      return "Rate-limit atingido (muitas mensagens)";
    case 500:
      return "Erro interno WhatsApp";
    case 503:
      return "WhatsApp temporariamente indisponível";
    default:
      return "Erro desconhecido na API Meta";
  }
}

/**
 * logger — grava logs no enova_log via proxy Vercel
 */
async function logger(env, data) {
  try {
    await sbFetch(env, "/rest/v1/enova_log", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      // NÃO inventa coluna "ts" aqui. Deixa o banco cuidar do created_at.
      body: JSON.stringify(data),
    });
  } catch (e) {
    console.error("Erro logger:", e);
  }
}

// =============================================================
// 🧱 A2 — supabaseProxyFetch + getState + upsertState (versão FINAL)
// =============================================================

// sbFetch agora apenas encaminha para o supabaseProxyFetch,
// mantendo assinatura e compatibilidade com o Worker inteiro.
async function sbFetch(env, path, options = {}, context = {}) {
  return await supabaseProxyFetch(env, {
    path,
    method: options.method || "GET",
    query: options.query || null,
    body: options.body || null,
    headers: {
      "Content-Type": "application/json",
      apikey: env.SUPABASE_SERVICE_ROLE,
      Authorization: `Bearer ${env.SUPABASE_SERVICE_ROLE}`
    }
  });
}

function normalizeSupabaseRows(result) {
  if (Array.isArray(result)) return result;
  if (result && Array.isArray(result.data)) return result.data;
  return [];
}

// =============================================================
// Lê o estado do funil (GET correto via Proxy V2)
// =============================================================
async function getState(env, wa_id) {
  const simCtx = getSimulationContext(env);
  if (simCtx?.active && simCtx.stateByWaId && simCtx.stateByWaId[wa_id]) {
    return simCtx.stateByWaId[wa_id];
  }

  const result = await sbFetch(
    env,
    "/rest/v1/enova_state",
    {
      method: "GET",
      query: {
        select: "*",
        wa_id: `eq.${encodeURIComponent(wa_id)}`
      }
    },
    { wa_id, stage: "get_state" }
  );

  if (Array.isArray(result)) {
    return result[0] || null;
  }

  if (result && Array.isArray(result.data)) {
    return result.data[0] || null;
  }

  console.error("getState: formato inesperado de resposta Supabase:", result);
  return null;
}

// =============================================================
// Atualiza ou cria estado do funil (UPSERT manual, sem 409)
// =============================================================
async function upsertState(env, wa_id, payload) {
  const result = await _upsertStateCore(env, wa_id, payload);
  // ── Metadados de perfil (não-bloqueante) ──────────────────────────────
  // Se o payload contém campos de perfil do cliente, registra source='funil'
  // em enova_prefill_meta. Falha silenciosa — nunca interfere no trilho.
  const profileFieldsInPayload = new Set(
    Object.keys(payload || {}).filter((k) => PROFILE_META_FIELDS.has(k))
  );
  if (profileFieldsInPayload.size > 0) {
    updateProfileFieldsMeta(env, wa_id, profileFieldsInPayload, "funil").catch(() => {});
  }
  return result;
}

async function _upsertStateCore(env, wa_id, payload) {
  const simCtx = getSimulationContext(env);
  const optionalMissingEnovaStateColumns = new Set([
    "last_message_id_prev",
    "last_message_timestamp",
    "dossie_sinais_persistidos_json",
    "pacote_sinais_persistidos_json",
    "envio_docs_itens_json"
  ]);
  // Initial attempt + one retry for each optional allowlisted column that may need removal.
  const MAX_OPTIONAL_FALLBACK_RETRIES = optionalMissingEnovaStateColumns.size + 1;

  // Sempre atualizamos o updated_at no Worker
  const patch = {
    ...payload,
    updated_at: new Date().toISOString()
  };

  if (simCtx?.active) {
    simCtx.writeLog = Array.isArray(simCtx.writeLog) ? simCtx.writeLog : [];
    simCtx.writeLog.push({ wa_id, patch });
    simCtx.writesByWaId = simCtx.writesByWaId || {};
    simCtx.writesByWaId[wa_id] = { ...(simCtx.writesByWaId[wa_id] || {}), ...patch };

    const current = simCtx.stateByWaId?.[wa_id] || { wa_id };
    const merged = { ...current, ...patch, wa_id };

    if (simCtx.stateByWaId) {
      simCtx.stateByWaId[wa_id] = merged;
    }

    if (simCtx.dryRun) {
      return merged;
    }
  }

  // Sanitize: não escrever coluna que não existe no Supabase

  try {
    // 1) Verifica se já existe registro para esse wa_id
    const existing = await getState(env, wa_id);

    // ---------------------------------------------------------
    // CASO 1: não existe ainda → tenta INSERT
    // ---------------------------------------------------------
    if (!existing) {
      let rowInsert = { wa_id, ...patch };

      for (let insertAttempt = 0; insertAttempt < MAX_OPTIONAL_FALLBACK_RETRIES; insertAttempt++) {
        try {
          const insertResult = await supabaseInsert(env, "enova_state", rowInsert);

          if (Array.isArray(insertResult)) {
            return insertResult[0] || null;
          }
          if (insertResult && Array.isArray(insertResult.data)) {
            return insertResult.data[0] || null;
          }
          return insertResult || null;
        } catch (err) {
          const missingColumn = extractMissingEnovaStateColumnFromSupabaseError(err);
          if (
            optionalMissingEnovaStateColumns.has(missingColumn) &&
            Object.prototype.hasOwnProperty.call(rowInsert, missingColumn)
          ) {
            const { [missingColumn]: _ignoredMissingColumn, ...fallbackPatch } = rowInsert;
            rowInsert = fallbackPatch;
            continue;
          }
          // Se bater 409 aqui, significa que alguém inseriu
          // na frente – então convertemos em UPDATE e segue a vida
          if (err.status === 409) {
            const { wa_id: _ignoredWaId, ...initialUpdatePatch } = rowInsert;
            let updatePatch = initialUpdatePatch;
            for (let updateAttempt = 0; updateAttempt < MAX_OPTIONAL_FALLBACK_RETRIES; updateAttempt++) {
              try {
                const updateResult = await supabaseUpdate(
                  env,
                  "enova_state",
                  { wa_id },
                  updatePatch
                );

                if (Array.isArray(updateResult)) {
                  return updateResult[0] || null;
                }
                if (updateResult && Array.isArray(updateResult.data)) {
                  return updateResult.data[0] || null;
                }
                return updateResult || null;
              } catch (updateErr) {
                const missingColumn = extractMissingEnovaStateColumnFromSupabaseError(updateErr);
                if (
                  optionalMissingEnovaStateColumns.has(missingColumn) &&
                  Object.prototype.hasOwnProperty.call(updatePatch, missingColumn)
                ) {
                  const { [missingColumn]: _ignoredMissingColumn, ...fallbackPatch } = updatePatch;
                  updatePatch = fallbackPatch;
                  continue;
                }
                throw updateErr;
              }
            }
          }

          console.error(
            `upsertState: erro no INSERT para wa_id=${wa_id}`,
            err
          );
          throw err;
        }
      }
    }

    // ---------------------------------------------------------
    // CASO 2: já existe registro → UPDATE direto
    // ---------------------------------------------------------
    let updatePatch = { ...patch };
    for (let updateAttempt = 0; updateAttempt < MAX_OPTIONAL_FALLBACK_RETRIES; updateAttempt++) {
      try {
        const updateResult = await supabaseUpdate(
          env,
          "enova_state",
          { wa_id },
          updatePatch
        );

        if (Array.isArray(updateResult)) {
          return updateResult[0] || null;
        }
        if (updateResult && Array.isArray(updateResult.data)) {
          return updateResult.data[0] || null;
        }
        return updateResult || null;
      } catch (err) {
        const missingColumn = extractMissingEnovaStateColumnFromSupabaseError(err);
        if (
          optionalMissingEnovaStateColumns.has(missingColumn) &&
          Object.prototype.hasOwnProperty.call(updatePatch, missingColumn)
        ) {
          const { [missingColumn]: _ignoredMissingColumn, ...fallbackPatch } = updatePatch;
          updatePatch = fallbackPatch;
          continue;
        }
        throw err;
      }
    }
  } catch (err) {
    console.error(
      `upsertState: erro geral para wa_id=${wa_id}`,
      err
    );
    // 🚨 INCIDENT — persistence failure (objective proof: Supabase upsert exception)
    try { await openIncidentIfNeeded(env, { wa_id, fase_conversa: payload?.fase_conversa }, { incident_type: "PERSISTENCE_FAILURE", incident_severity: "CRITICAL", error_message_short: "Falha de persistência no upsertState", error_message_raw: err?.stack || String(err), suspected_trigger: "upsertState_catch" }); } catch (_) { /* non-blocking */ }
    throw err;
  }
}

function extractMissingEnovaStateColumnFromSupabaseError(err) {
  const status = Number(err?.status || 0);
  const data = err?.data;
  if (status !== 400 || !data || typeof data !== "object") return null;
  const combinedErrorText = [
    data?.message,
    data?.details,
    data?.hint
  ].filter(Boolean).join(" ");
  const match = combinedErrorText.match(/Could not find the '([^']+)' column of 'enova_state' in the schema cache/i);
  return match?.[1] || null;
}

